    REQUIRE(cell.has_next());
    REQUIRE(cell.width_twips().has_value());
    CHECK_EQ(*cell.width_twips(), 3300U);
    cell.next();
    REQUIRE(cell.has_next());
    REQUIRE(cell.width_twips().has_value());
    CHECK_EQ(*cell.width_twips(), 2400U);

    row.next();
    REQUIRE(row.has_next());
    cell = row.cells();
    REQUIRE(cell.has_next());
    REQUIRE(cell.width_twips().has_value());
    CHECK_EQ(*cell.width_twips(), 1200U);
    cell.next();
    REQUIRE(cell.has_next());
    REQUIRE(cell.width_twips().has_value());
    CHECK_EQ(*cell.width_twips(), 2100U);
    cell.next();
    REQUIRE(cell.has_next());
    REQUIRE(cell.width_twips().has_value());
    CHECK_EQ(*cell.width_twips(), 2400U);

